// src/components/Settings.js
import React, { useState } from 'react';
import './Settings.css';

const AdminLogin = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showStudentManagement, setShowStudentManagement] = useState(false);

  const handleLogin = (e) => {
    e.preventDefault();
    if (username === ' ' && password === ' ') { // Change to actual credentials
      setIsLoggedIn(true);
    } else {
      alert('Invalid credentials');
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUsername('');
    setPassword('');
    setShowStudentManagement(false);
  };

  return (
    <div className="admin-layout">
      {!isLoggedIn ? (
        <div className="admin-login-container">
          <h2>Admin Login</h2>
          <form onSubmit={handleLogin}>
            <div className="input-group">
              <label>Username:</label>
              <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} required />
            </div>
            <div className="input-group">
              <label>Password:</label>
              <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required />
            </div>
            <div className="button-container">
              <button type="submit">Login</button>
            </div>
          </form>
        </div>
      ) : (
        <div className="admin-panel-wrapper">
          {!showStudentManagement ? (
            <>
              <div className="admin-panel duplicated">
                <h3>Admin Panel</h3>
                <p>Modify Admin Password and Update Admin Data.</p>
                <button className="settings-button">Go to Settings</button>
              </div>
              <div className="admin-panel">
                <h3>Student Management</h3>
                <p>Modify Student Data (Add, Edit, Delete)</p>
                <button onClick={() => setShowStudentManagement(true)} className="settings-button">
                  Manage Students
                </button>
              </div>
              <button onClick={handleLogout} className="back-button">Back to Login</button>
            </>
          ) : (
            <div className={`admin-panel-wrapper ${showStudentManagement ? 'hidden-panel' : 'visible-panel'}`}>

              <h2>Student Management</h2>
              <button>Add Student</button>
              <button>Edit Student</button>
              <button>Delete Student</button>
              <button onClick={() => setShowStudentManagement(false)} className="back-button">
                Back to Admin Panel
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default AdminLogin;
